  A:      {label:"Ace",     cls:"sym-royal sym-a",  weight:6,   render:()=><LbSymRoyal letter="A" color="#f5c400"/>},
  K:      {label:"King",    cls:"sym-royal sym-k",  weight:8,   render:()=><LbSymRoyal letter="K" color="#e8a030"/>},
  Q:      {label:"Queen",   cls:"sym-royal sym-q",  weight:10,  render:()=><LbSymRoyal letter="Q" color="#c080e0"/>},
